        print "Output context: ..." . substr($output,$start,$end_out-$start) . "...\n";
        last;
    }
}

# Find last difference (from end)
for my $i (0..length($input)-1) {
    my $j = length($input) - 1 - $i;
    my $k = length($output) - 1 - $i;
    if ($j < 0 || $k < 0) { last; }
    if (substr($input,$j,1) ne substr($output,$k,1)) {
        print "Last difference at position $j (input)\n";
        my $start = $j > 20 ? $j-20 : 0;
        my $end = $j+20 < length($input) ? $j+20 : length($input);
        print "Input context:  ..." . substr($input,$start,$end-$start) . "...\n";
        last;
    }
}

# Find the exact inserted region in output
# Walk from start to find where they diverge, then walk from end
my $start_diff = -1;
for my $i (0..length($input)-1) {
    if ($i >= length($output)) { last; }
    if (substr($input,$i,1) ne substr($output,$i,1)) {
        $start_diff = $i;
        last;
    }
}

my $end_diff_in = -1;
for my $i (0..length($input)-1) {
    my $j = length($input) - 1 - $i;
    my $k = length($output) - 1 - $i;
    if ($j < 0 || $k < 0) { last; }
    if (substr($input,$j,1) ne substr($output,$k,1)) {
        $end_diff_in = $j;
        last;
    }
}

if ($start_diff >= 0 && $end_diff_in >= 0) {
    print "\nInput deleted region: pos $start_diff to $end_diff_in\n";
    print "Input deleted: " . substr($input,$start_diff,$end_diff_in-$start_diff+1) . "\n";

    # Find corresponding region in output
    my $start_out = $start_diff;
    my $len_diff = length($output) - length($input);
    my $end_out = $start_out + ($end_diff_in - $start_diff) + 1 + $len_diff;
    print "Output inserted region: pos $start_out to $end_out\n";
    print "Output inserted: " . substr($output,$start_out,$end_out-$start_out) . "\n";
}
'
"}

