{"path":"analyze.pl","content":"#!/usr/bin/perl
use strict;
use warnings;

# Parse sequences
open(F, "sequences.fasta") or die;
my $content = do { local $/; <F> };
close(F);

my @lines = split /\n/, $content;
my %seqs;
my $cur = "";
for my $l (@lines) {
    if ($l =~ /^>(\S+)/) {
        $cur = $1;
        $seqs{$cur} = "";
    } else {
        $seqs{$cur} .= lc($l);
    }
}

my $input = $seqs{"input"};
my $output = $seqs{"output"};

# Find insertion point
my $start_diff = -1;
for my $i (0..length($input)-1) {
    if ($i >= length($output)) { last; }
    if (substr($input,$i,1) ne substr($output,$i,1)) {
        $start_diff = $i;
        last;
    }
}

my $insertion = substr($output, $start_diff, length($output) - length($input));
print "Insertion at position $start_diff: $insertion\n";
print "Insertion length: " . length($insertion) . "\n";

# For Q5 SDM with a circular plasmid:
# Forward primer: 5'-[insertion sequence][annealing region matching template from start_diff]-3'
# The annealing part of the forward primer matches the output/input sequence starting at start_diff
# It binds to the antisense strand (template) going downstream

# Reverse primer: 5'-[revcomp(insertion)][annealing region on sense strand before start_diff]-3'  
# The annealing part is revcomp of input sequence ending just before start_diff
# It binds to the sense strand going upstream

# Forward primer structure:
#   [insertion] + [annealing to template at position start_diff onwards]
# Annealing region length: 15-45 nt
# The annealing part = output[start_diff : start_diff+L] for forward primer

# Reverse primer structure:
#   [revcomp(insertion)] + [annealing to template at position (start_diff-L) to start_diff-1]
# Annealing region length: 15-45 nt
# The annealing part = revcomp(input[start_diff-L : start_diff])

# Print context sequences
print "\nContext around insertion:\n";
my $ctx_start = $start_diff > 30 ? $start_diff - 30 : 0;
print "Input:  ..." . substr($input, $ctx_start, $start_diff - $ctx_start) . "|[INSERTION]|" . substr($input, $start_diff, 30) . "...\n";
print "Output: ..." . substr($output, $ctx_start, $start_diff - $ctx_start) . "|$insertion|" . substr($output, $start_diff + length($insertion), 30) . "...\n";

# For the forward primer:
# annealing region = output[start_diff : start_diff+L] (matches template downstream)
# full primer = insertion + output[start_diff : start_diff+L]

# For the reverse primer:
# annealing region = revcomp(input[start_diff-L : start_diff]) (matches template upstream)
# full primer = revcomp(insertion) + revcomp(input[start_diff-L : start_diff])

sub revcomp {
    my ($seq) = @_;
    my $rc = reverse($seq);
    $rc =~ tr/ACGTacgt/TGCAtgca/;
    return $rc;
}

# Test with different annealing lengths
print "\nTesting primer designs:\n";
for my $L (15..45) {
    # Forward primer annealing region
    my $f_anneal = substr($output, $start_diff, $L);
    my $f_primer = $insertion . $f_anneal;

    # Reverse primer annealing region (on input template, upstream of insertion)
    my $r_anneal_seq = substr($input, $start_diff - $L, $L);
    my $r_anneal = revcomp($r_anneal_seq);
    my $r_primer = revcomp($insertion) . $r_anneal;

    print "Annealing length $L:\n";
    print "  Forward: $f_primer (len=" . length($f_primer) . ")\n";
    print "  Reverse: $r_primer (len=" . length($r_primer) . ")\n";
}
"}

{"path":"find_primers.pl","content":"#!/usr/bin/perl
use strict;
use warnings;

# Parse sequences
open(F, "sequences.fasta") or die;
my $content = do { local $/; <F> };
close(F);

my @lines = split /\n/, $content;
my %seqs;
my $cur = "";
for my $l (@lines) {
    if ($l =~ /^>(\S+)/) {
        $cur = $1;
        $seqs{$cur} = "";
    } else {
        $seqs{$cur} .= lc($l);
    }
}

my $input = $seqs{"input"};
my $output = $seqs{"output"};

# Find insertion point
my $start_diff = -1;
for my $i (0..length($input)-1) {
    if ($i >= length($output)) { last; }
    if (substr($input,$i,1) ne substr($output,$i,1)) {
        $start_diff = $i;
        last;
    }
}

my $insertion = substr($output, $start_diff, length($output) - length($input));

sub revcomp {
    my ($seq) = @_;
    my $rc = reverse($seq);
    $rc =~ tr/ACGTacgt/TGCAtgca/;
    return $rc;
}

# For each annealing length L (15-45):
# Forward primer annealing region: output[start_diff : start_diff+L]
# Reverse primer annealing region: revcomp(input[start_diff-L : start_diff])
# We need to compute Tm of just the annealing parts using oligotm

my @results;

for my $L (15..45) {
    # Forward primer annealing region
    my $f_anneal = substr($output, $start_diff, $L);

    # Reverse primer annealing region (on input template, upstream of insertion)
    my $r_anneal_seq = substr($input, $start_diff - $L, $L);
    my $r_anneal = revcomp($r_anneal_seq);

    # Compute Tm using oligotm with specified flags
    my $f_tm_cmd = "oligotm -tp 1 -sc 1 -mv 50 -dv 2 -n 0.8 -d 500 $f_anneal";
    my $r_tm_cmd = "oligotm -tp 1 -sc 1 -mv 50 -dv 2 -n 0.8 -d 500 $r_anneal";

    open(my $fh, "$f_tm_cmd |") or die;
    my $f_tm = <$fh>;
    close($fh);
    chomp($f_tm);

    open($fh, "$r_tm_cmd |") or die;
    my $r_tm = <$fh>;
    close($fh);
    chomp($r_tm);

    $f_tm += 0;
    $r_tm += 0;

    my $tm_diff = abs($f_tm - $r_tm);

    # Check constraints
    my $valid = 1;
    if ($f_tm < 58 || $f_tm > 72) { $valid = 0; }
    if ($r_tm < 58 || $r_tm > 72) { $valid = 0; }
    if ($tm_diff > 5) { $valid = 0; }

    my $status = $valid ? "VALID" : "INVALID";
    push @results, [$L, $f_anneal, $r_anneal, $f_tm, $r_tm, $tm_diff, $valid];

    printf "L=%2d | F_anneal_Tm=%.1f R_anneal_Tm=%.1f | diff=%.1f | %s\n",
        $L, $f_tm, $r_tm, $tm_diff, $status;
}

# Find best valid pair (prefer shortest total primer length)
my @valid = grep { $_->[6] } @results;
if (@valid) {
    # Sort by total primer length (insertion + 2*L)
    @valid = sort { ($39 + 2*$a->[0]) <=> ($39 + 2*$b->[0]) } @valid;
    my $best = $valid[0];

    my $L = $best->[0];
    my $f_anneal = $best->[1];
    my $r_anneal = $best->[2];
    my $f_tm = $best->[3];
    my $r_tm = $best->[4];

    my $f_primer = $insertion . $f_anneal;
    my $r_primer = revcomp($insertion) . $r_anneal;

    print "\n=== BEST PAIR ===\n";
    print "Annealing length: $L\n";
    print "Forward primer: $f_primer (len=" . length($f_primer) . ", Tm=$f_tm)\n";
    print "Reverse primer: $r_primer (len=" . length($r_primer) . ", Tm=$r_tm)\n";

    # Write output
    open(OUT, ">primers.fasta") or die;
    printf OUT ">forward_primer\n%s\n", $f_primer;
    printf OUT ">reverse_primer\n%s\n", $r_primer;
    close(OUT);

    print "Written to primers.fasta\n";
} else {
    print "\nNo valid primer pair found!\n";
}
"}

